import styled, {css} from 'styled-components';
import CustomButton from '../custom-button/custom-button.component';



var buttonVisible = 'hidden';

const hoverButton = () => (
     buttonVisible = 'visible'
)

const CollectionItemCss = css`
width: 22vw;
display: flex;
flex-direction: column;
height: 350px;
align-items: center;
position: relative;

&:hover{
    border: 1px solid black;
  }
`


export const CollectionItemContainer = styled.div`
    ${CollectionItemCss}
`

export const CustomButtonStyled = styled(CustomButton)`
    width: 80%;
    opacity: 0.7;
    position: absolute;
    top: 255px;
    visibility: ${buttonVisible};
`

export const CollectionImage = styled.image`
    width: 100%;
    height: 95%;
    background-size: cover;
    background-position: center;
    margin-bottom: 5px;            
`

export const CollectionFooter = styled.div`
    width: 100%;
    height: 5%;
    display: flex;
    justify-content: space-between;
    font-size: 18px;
`

export const CollectionName = styled.span`
    width: 90%;
    margin-bottom: 15px;
`

export const CollectionPrice = styled.span`
    width: 10%;
`
